import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './App.css';
import { marked } from 'marked';

function App() {
  const [user, setUser] = useState(null);
  const [message, setMessage] = useState('');
  const [chats, setChats] = useState([]);
  const [files, setFiles] = useState([]);
  const [filePreviews, setFilePreviews] = useState([]);
  const [authModal, setAuthModal] = useState(false);
  const [authTab, setAuthTab] = useState('login');
  const [agents, setAgents] = useState([]);
  const [subscriptions, setSubscriptions] = useState([]);
  const [showAgentModal, setShowAgentModal] = useState(false);
  const [showPlanModal, setShowPlanModal] = useState(false);
  const [showFileUpload, setShowFileUpload] = useState(false);
  const [languageDropdown, setLanguageDropdown] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const chatEndRef = useRef(null);
  const fileInputRef = useRef(null);

  // Check authentication status
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      axios.get('/api/profile', {
        headers: { Authorization: `Bearer ${token}` }
      })
      .then(res => {
        setUser(res.data);
        loadChatHistory(token);
      })
      .catch(() => {
        localStorage.removeItem('token');
        setUser(null);
      });
    }
    
    // Load initial data
    axios.get('/api/agents')
      .then(res => setAgents(res.data))
      .catch(err => console.error('Error loading agents:', err));

    axios.get('/api/subscriptions')
      .then(res => setSubscriptions(res.data))
      .catch(err => console.error('Error loading subscriptions:', err));
  }, []);

  // Scroll to bottom of chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chats]);

  const loadChatHistory = (token) => {
    axios.get('/api/chat/history', {
      headers: { Authorization: `Bearer ${token}` }
    })
    .then(res => setChats(res.data))
    .catch(err => console.error('Error loading chat history:', err));
  };

  const register = async (e) => {
    e.preventDefault();
    const form = e.target;
    const name = form.name.value;
    const email = form.email.value;
    const password = form.password.value;
    const confirmPassword = form.confirmPassword.value;

    if (password !== confirmPassword) {
      alert('Passwords do not match');
      return;
    }

    try {
      const res = await axios.post('/api/register', {
        name,
        email,
        password
      });
      
      localStorage.setItem('token', res.data.token);
      setUser(res.data.user);
      setAuthModal(false);
      loadChatHistory(res.data.token);
    } catch (err) {
      alert(err.response?.data?.error || 'Registration failed');
    }
  };

  const login = async (e) => {
    e.preventDefault();
    const form = e.target;
    try {
      const res = await axios.post('/api/login', {
        email: form.email.value,
        password: form.password.value
      });
      
      localStorage.setItem('token', res.data.token);
      setUser(res.data.user);
      setAuthModal(false);
      loadChatHistory(res.data.token);
    } catch (err) {
      alert(err.response?.data?.error || 'Login failed');
    }
  };

  const logout = async () => {
    try {
      await axios.post('/api/logout', {}, {
        headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
      });
      localStorage.removeItem('token');
      setUser(null);
      setChats([]);
    } catch (err) {
      console.error('Logout error:', err);
    }
  };

  const handleFileChange = (e) => {
    const newFiles = Array.from(e.target.files);
    if (files.length + newFiles.length > 5) {
      alert('You can upload a maximum of 5 files');
      return;
    }

    setFiles([...files, ...newFiles]);
    
    const previews = newFiles.map(file => ({
      name: file.name,
      type: file.type.split('/')[1] || file.type,
      size: (file.size / 1024 / 1024).toFixed(2) + 'MB'
    }));
    
    setFilePreviews([...filePreviews, ...previews]);
  };

  const removeFile = (index) => {
    const newFiles = [...files];
    newFiles.splice(index, 1);
    setFiles(newFiles);
    
    const newPreviews = [...filePreviews];
    newPreviews.splice(index, 1);
    setFilePreviews(newPreviews);
  };

  const sendMessage = async () => {
    if (!message.trim() && files.length === 0) return;
    
    setIsLoading(true);
    const formData = new FormData();
    formData.append('message', message);
    files.forEach(file => formData.append('files', file));
    
    try {
      const res = await axios.post('/api/chat', formData, {
        headers: {
          'Authorization': `Bearer ${localStorage.getItem('token')}`,
          'Content-Type': 'multipart/form-data'
        }
      });
      
      setChats([...chats, res.data]);
      setMessage('');
      setFiles([]);
      setFilePreviews([]);
      setShowFileUpload(false);
    } catch (err) {
      console.error('Error sending message:', err);
      alert(err.response?.data?.error || 'Failed to send message');
    } finally {
      setIsLoading(false);
    }
  };

  const subscribe = async (planId) => {
    if (!user) {
      setAuthModal(true);
      setShowPlanModal(false);
      return;
    }
    
    try {
      await axios.post('/api/subscribe', { planId }, {
        headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
      });
      alert(`Subscribed to ${planId} plan successfully!`);
      setShowPlanModal(false);
      
      // Refresh user data
      const res = await axios.get('/api/profile', {
        headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
      });
      setUser(res.data);
    } catch (err) {
      alert(err.response?.data?.error || 'Subscription failed');
    }
  };

  const toggleFileUpload = () => {
    setShowFileUpload(!showFileUpload);
  };

  const triggerFileInput = () => {
    fileInputRef.current.click();
  };

  const toggleLanguageDropdown = () => {
    setLanguageDropdown(!languageDropdown);
  };

  const changeLanguage = (lang) => {
    alert(`Language changed to ${lang}`);
    setLanguageDropdown(false);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <div className="app-container">
      {/* Header */}
      <header className="header">
        <div className="header-brand">
          <img 
            src="https://i.ibb.co/pjR8wxhR/ai-mmi-logo-dark-background.png" 
            alt="AI-MMI Logo" 
            className="header-icon" 
          />
          <h1 className="header-title">AI-MMI</h1>
        </div>
        
        <div className="header-controls">
          <div className={`language-dropdown ${languageDropdown ? 'active' : ''}`}>
            <img 
              src="https://i.ibb.co/tMDdT4bd/icon-lang.png" 
              alt="Language" 
              className="header-icon" 
              onClick={toggleLanguageDropdown}
            />
            {languageDropdown && (
              <div className="language-options">
                <button onClick={() => changeLanguage('en')}>English</button>
                <button onClick={() => changeLanguage('zh')}>中文</button>
                <button onClick={() => changeLanguage('es')}>Español</button>
                <button onClick={() => changeLanguage('fr')}>Français</button>
              </div>
            )}
          </div>
          
          {user ? (
            <>
              <span className="welcome">Welcome, {user.name}</span>
              <button onClick={logout} className="btn-logout">
                Logout
              </button>
            </>
          ) : (
            <button onClick={() => setAuthModal(true)} className="btn-login">
              Login
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="main-content">
        {/* Chat Container */}
        <div className="chat-container">
          <div className="chat-history">
            {chats.length === 0 ? (
              <div className="welcome-message">
                <h2>Welcome to AI-MMI Immigration Assistant</h2>
                <p>Ask me anything about visas, immigration processes, or upload your documents for analysis.</p>
                {!user && (
                  <button 
                    onClick={() => setAuthModal(true)} 
                    className="btn-primary"
                  >
                    Login to Start Chatting
                  </button>
                )}
              </div>
            ) : (
              chats.map((chat, index) => (
                <div key={index} className={`message ${chat.user === user?._id ? 'user-message' : 'ai-message'}`}>
                  {chat.message && (
                    <div dangerouslySetInnerHTML={{ __html: marked.parse(chat.message) }} />
                  )}
                  {chat.response && (
                    <div dangerouslySetInnerHTML={{ __html: marked.parse(chat.response) }} />
                  )}
                  {chat.files?.length > 0 && (
                    <div className="file-attachments">
                      <small>Attachments: {chat.files.length}</small>
                    </div>
                  )}
                  <div className="timestamp">
                    {new Date(chat.timestamp).toLocaleString()}
                  </div>
                </div>
              ))
            )}
            <div ref={chatEndRef} />
          </div>
          
          {/* Input Area */}
          {user && (
            <div className="input-area">
              {showFileUpload && (
                <div className="file-previews">
                  {filePreviews.length > 0 && (
                    <>
                      {filePreviews.map((file, index) => (
                        <div key={index} className="file-preview">
                          <i className={`fas ${
                            file.type.includes('pdf') ? 'fa-file-pdf' :
                            file.type.includes('word') ? 'fa-file-word' :
                            file.type.includes('text') ? 'fa-file-alt' :
                            file.type.includes('image') ? 'fa-file-image' : 'fa-file'
                          }`}></i>
                          <span className="file-name">{file.name}</span>
                          <span className="file-info">{file.size}</span>
                          <button 
                            onClick={() => removeFile(index)} 
                            className="btn-remove"
                          >
                            <i className="fas fa-times"></i>
                          </button>
                        </div>
                      ))}
                    </>
                  )}
                  <button 
                    onClick={triggerFileInput}
                    className="btn-attach"
                  >
                    <i className="fas fa-plus"></i> Add Files
                  </button>
                  <input
                    type="file"
                    ref={fileInputRef}
                    multiple
                    onChange={handleFileChange}
                    style={{ display: 'none' }}
                    accept=".pdf,.doc,.docx,.txt,.jpg,.jpeg,.png"
                  />
                  <p className="file-upload-note">
                    Supported: PDF, Word, TXT, PNG, JPG (Max 5MB each)
                  </p>
                </div>
              )}
              
              <div className="input-group">
                <button 
                  className="btn-attach" 
                  onClick={toggleFileUpload}
                  title="Attach files"
                >
                  <i className="fas fa-paperclip"></i>
                </button>
                
                <input
                  type="text"
                  value={message}
                  onChange={(e) => setMessage(e.target.value)}
                  placeholder="Type your immigration question..."
                  onKeyPress={handleKeyPress}
                  disabled={isLoading}
                />
                
                <button 
                  onClick={sendMessage} 
                  className="btn-send"
                  disabled={(!message.trim() && files.length === 0) || isLoading}
                  title="Send message"
                >
                  {isLoading ? (
                    <i className="fas fa-spinner fa-spin"></i>
                  ) : (
                    <i className="fas fa-paper-plane"></i>
                  )}
                </button>
              </div>
            </div>
          )}
        </div>
        
        {/* Sidebar */}
        <div className="sidebar">
          <div className="sidebar-section">
            <h3>Quick Actions</h3>
            <button 
              className="sidebar-btn"
              onClick={() => setShowAgentModal(true)}
            >
              <i className="fas fa-user-tie"></i> Contact Agent
            </button>
            <button 
              className="sidebar-btn"
              onClick={() => setShowPlanModal(true)}
            >
              <i className="fas fa-crown"></i> Subscription Plans
            </button>
          </div>
          
          <div className="sidebar-section">
            <h3>Resources</h3>
            <button className="sidebar-btn">
              <i className="fas fa-file-alt"></i> My Documents
            </button>
            <button className="sidebar-btn">
              <i className="fas fa-search"></i> Search Chats
            </button>
            <button className="sidebar-btn">
              <i className="fas fa-star"></i> Recommendations
            </button>
          </div>
          
          {user && (
            <div className="sidebar-section">
              <h3>Account</h3>
              <button className="sidebar-btn">
                <i className="fas fa-user"></i> My Profile
              </button>
              <button className="sidebar-btn" onClick={logout}>
                <i className="fas fa-sign-out-alt"></i> Logout
              </button>
            </div>
          )}
        </div>
      </main>

      {/* Auth Modal */}
      {authModal && (
        <div className="modal-overlay">
          <div className="modal-content">
            <div className="modal-header">
              <h2>{authTab === 'login' ? 'Login' : 'Sign Up'}</h2>
              <button 
                className="btn-close"
                onClick={() => setAuthModal(false)}
              >
                &times;
              </button>
            </div>
            
            <div className="modal-tabs">
              <button 
                className={authTab === 'login' ? 'active' : ''}
                onClick={() => setAuthTab('login')}
              >
                Login
              </button>
              <button 
                className={authTab === 'register' ? 'active' : ''}
                onClick={() => setAuthTab('register')}
              >
                Sign Up
              </button>
            </div>
            
            {authTab === 'login' ? (
              <form onSubmit={login} className="auth-form">
                <div className="form-group">
                  <label htmlFor="email">Email</label>
                  <input 
                    type="email" 
                    id="email" 
                    name="email"
                    required 
                    placeholder="Enter your email" 
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="password">Password</label>
                  <input 
                    type="password" 
                    id="password" 
                    name="password"
                    required 
                    placeholder="Enter your password" 
                  />
                </div>
                <button type="submit" className="btn-primary">
                  Login
                </button>
              </form>
            ) : (
              <form onSubmit={register} className="auth-form">
                <div className="form-group">
                  <label htmlFor="name">Full Name</label>
                  <input 
                    type="text" 
                    id="name" 
                    name="name"
                    required 
                    placeholder="Enter your full name" 
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="email">Email</label>
                  <input 
                    type="email" 
                    id="email" 
                    name="email"
                    required 
                    placeholder="Enter your email" 
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="password">Password</label>
                  <input 
                    type="password" 
                    id="password" 
                    name="password"
                    required 
                    placeholder="Create a password" 
                  />
                </div>
                <div className="form-group">
                  <label htmlFor="confirmPassword">Confirm Password</label>
                  <input 
                    type="password" 
                    id="confirmPassword" 
                    name="confirmPassword"
                    required 
                    placeholder="Confirm your password" 
                  />
                </div>
                <button type="submit" className="btn-primary">
                  Sign Up
                </button>
              </form>
            )}
          </div>
        </div>
      )}

      {/* Agent Modal */}
      {showAgentModal && (
        <div className="modal-overlay">
          <div className="modal-content agent-modal">
            <div className="modal-header">
              <h2>Contact a Migration Expert</h2>
              <button 
                className="btn-close"
                onClick={() => setShowAgentModal(false)}
              >
                &times;
              </button>
            </div>
            
            <div className="modal-body">
              <p>Connect with our network of registered migration agents and lawyers for personalized assistance with your case.</p>
              
              {agents.length > 0 ? (
                <div className="agent-list">
                  {agents.map(agent => (
                    <div key={agent._id} className="agent-card">
                      <h3>{agent.company}</h3>
                      {agent.name && <p><strong>Agent:</strong> {agent.name}</p>}
                      <p><strong>Email:</strong> {agent.email}</p>
                      <p><strong>Phone:</strong> {agent.phone}</p>
                      {agent.registration && <p><strong>Registration:</strong> {agent.registration}</p>}
                      {agent.countries?.length > 0 && (
                        <p><strong>Countries:</strong> {agent.countries.join(', ')}</p>
                      )}
                      <button 
                        className="btn-contact"
                        onClick={() => {
                          if (!user) {
                            setAuthModal(true);
                            setShowAgentModal(false);
                          } else {
                            alert(`Connecting you with ${agent.company}...`);
                          }
                        }}
                      >
                        Contact Agent
                      </button>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="no-agents">
                  <p>No agents available at the moment.</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Plan Modal */}
      {showPlanModal && (
        <div className="modal-overlay">
          <div className="modal-content plan-modal">
            <div className="modal-header">
              <h2>Subscription Plans</h2>
              <button 
                className="btn-close"
                onClick={() => setShowPlanModal(false)}
              >
                &times;
              </button>
            </div>
            
            <div className="modal-body">
              <p>Choose a plan that fits your immigration needs:</p>
              
              <div className="plan-list">
                {subscriptions.map(plan => (
                  <div key={plan.id} className={`plan-card ${plan.id}`}>
                    <div className="plan-header">
                      <h3>{plan.name}</h3>
                      <div className="plan-price">
                        ${plan.price} <span>/ month</span>
                      </div>
                    </div>
                    <ul className="plan-features">
                      {plan.features.map((feature, index) => (
                        <li key={index}>
                          <i className="fas fa-check"></i> {feature}
                        </li>
                      ))}
                    </ul>
                    <button 
                      className="btn-subscribe"
                      onClick={() => subscribe(plan.id)}
                    >
                      Subscribe to {plan.name}
                    </button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
